        entity.HasDiscriminator<string>("Discriminator");

        // EF9: id values changed from "Product|123" to "123".
        // Existing documents use the compound format — preserve it.
        entity.HasRootDiscriminatorInJsonId(true);
    });
    // Removed HasIndex — EF9 Cosmos provider now throws on HasIndex.
    // Manage indexing via Azure Portal / Bicep / Terraform instead.
}

